-- Notification templates for job offers and job applications module
	-- Notification - Job offer status change
	 ('c79e5db6-d89d-487f-a4ff-6e2801f7ade5', NOW(), NOW(), '1', '1', NULL, 'Notification - Job offer status change', 'Template to notify job offer status changes.', 'Job offer status change: $stic_job_offers_name', 'Dear,\r\n\r\nThe status of the job offer $stic_job_offers_name has changed to $stic_job_offers_status.', 
	 '<p>Dear,</p>
	 <p>The status of the job offer <strong>$stic_job_offers_name</strong> has changed to <strong><span style="background-color: #f1c40f;">$stic_job_offers_status</span></strong></p>',
	 0, '1', 0, 'notification'),
	 -- Notification - Job application status change
	 ('8ec00c6b-6102-4eb4-a601-7cdb420676a3', NOW(), NOW(), '1', '1', NULL, 'Notification - Job application status change', 'Default template to notify job application status changes.', 'Job application status change: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $contact_full_name:\r\n\r\nThe status of your application for the job offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to $stic_job_applications_status.', '<p>Dear $contact_full_name:</p>\n<p>The status of your application for the job offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to $stic_job_applications_status.</p>', 0, '1', 0, 'notification'),
	 -- Job application - Notification - Accepted status
	 ('6a31f063-2d17-4fd6-aef1-9e15db0f7d11', NOW(), NOW(), '1', '1', NULL, 'Notification - Application accepted', 'Template to notify that a job application has been accepted.', 'Your application has been accepted: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $contact_full_name:\r\n\r\nWe are pleased to inform you that your application for the job offer $stic_job_applications_stic_job_applications_stic_job_offers_name has been accepted.\r\n\r\nCurrent status: $stic_job_applications_status.', '<p>Dear $contact_full_name:</p>\n<p>We are pleased to inform you that your application for the job offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has been accepted.</p>\n<p>Current status: <strong>$stic_job_applications_status</strong>.</p>', 0, '1', 0, 'notification'),
	-- Job application - Notification - Rejected or closed status
	 ('bb6fe9c6-8b74-4526-a0a8-a7f4fd8e5960', NOW(), NOW(), '1', '1', NULL, 'Notification - Application rejected or closed', 'Template to notify that a job application has been rejected or closed.', 'Update on your application: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $contact_full_name:\r\n\r\nWe regret to inform you that your application for the job offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to status $stic_job_applications_status.\r\n\r\nThank you for your interest.', '<p>Dear $contact_full_name:</p>\n<p>We regret to inform you that your application for the job offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to status <strong>$stic_job_applications_status</strong>.</p>\n<p>Thank you for your interest.</p>', 0, '1', 0, 'notification'),
	 -- Job offer - Notification - Deadline passed and status not closed
	('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Notification - Offer with expired closing date and not closed status', 'Template to notify the responsible user that the application closing date was yesterday and the status is not closed or similar.', 'Review job offer: application deadline passed - $stic_job_offers_name', 'Dear,\r\n\r\nThe job offer $stic_job_offers_name has an expired application closing date (yesterday) and is currently in status $stic_job_offers_status.\r\n\r\nPlease review the offer and update its status if applicable.', '<p>Dear,</p>\n<p>The job offer <strong>$stic_job_offers_name</strong> has an expired application closing date (yesterday) and is currently in status <strong>$stic_job_offers_status</strong>.</p>\n<p>Please review the offer and update its status if applicable.</p>', 0, '1', 0, 'notification');

